<?php
namespace Tests\Feature;use App\Domain\Characters\CharacterStatsCalculator;use App\Domain\Equipment\CharacterEquipmentService;use App\Domain\Equipment\EquippableItemValidator;use App\Models\Character;use App\Models\Item;use App\Models\ItemInstance;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
final class EquipmentAbsorbDamageTest extends TestCase{use RefreshDatabase;public function test_only_equipped_item_contributes_absorb_and_unequip_reverts_it(){$character=Character::factory()->for(User::factory())->create();$item=Item::create(['code'=>'absorb_shield','name'=>'Absorb shield','item_type'=>'equipment','equipment_type'=>'weapon','hand_requirement'=>'off_hand_only','equipment_family'=>'shield','rarity'=>'common','is_stackable'=>false,'max_stack'=>1,'status'=>'active','absorb_damage_basis_points'=>500]);$instance=ItemInstance::factory()->create(['character_id'=>$character->id,'item_id'=>$item->id]);$this->assertSame(0,app(CharacterStatsCalculator::class)->calculate($character)->absorbDamageBasisPoints());app(CharacterEquipmentService::class)->equip($character,$instance->uuid,'off_hand');$this->assertSame(500,app(CharacterStatsCalculator::class)->calculate($character)->absorbDamageBasisPoints());app(CharacterEquipmentService::class)->unequip($character,'off_hand');$this->assertSame(0,app(CharacterStatsCalculator::class)->calculate($character)->absorbDamageBasisPoints());}public function test_absorb_is_not_refined_and_non_equipment_or_over_ten_percent_is_rejected(){$valid=new Item(['item_type'=>'equipment','equipment_type'=>'armor','is_stackable'=>false,'max_stack'=>1,'absorb_damage_basis_points'=>500]);$this->assertSame(500,app(EquippableItemValidator::class)->bonuses($valid)->absorbDamageBasisPoints());foreach([new Item(['item_type'=>'material','equipment_type'=>null,'is_stackable'=>true,'max_stack'=>10,'absorb_damage_basis_points'=>100]),new Item(['item_type'=>'equipment','equipment_type'=>'armor','is_stackable'=>false,'max_stack'=>1,'absorb_damage_basis_points'=>1001])]as$item){try{app(EquippableItemValidator::class)->bonuses($item);$this->fail('Invalid AbsorbDamage accepted.');}catch(\InvalidArgumentException $e){$this->assertNotEmpty($e->getMessage());}}}}
